import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import './App.css';

// Constants & Utils
import { SOCKET_URL, CELL, SHIPS } from './constants';
import {
  createEmptyBoard,
  getRoomFromURL,
  setURLRoom,
  getSurroundingKeys
} from './utils/gameHelpers';
import { playSound } from './utils/sounds';
import { playPhaseMusic, stopAllMusic, setMusicEnabled, pauseMusic, resumeMusic } from './utils/music';

// Components
import ShipPlacement from './components/ShipPlacement';
import LoginView from './components/LoginView';
import WaitingRoom from './components/WaitingRoom';
import BattleField from './components/BattleField';
import GameOver from './components/GameOver';
import ChatBox from './components/ChatBox';
import ConnectionOverlay from './components/ConnectionOverlay';

// Hooks
import useSocket from './hooks/useSocket';

function App() {
  const { socket, isConnected } = useSocket();
  const urlInfo = useMemo(() => getRoomFromURL(), []);

  // State
  const [gameId, setGameId] = useState(urlInfo.roomCode || '');
  const [roomPassword, setRoomPassword] = useState(urlInfo.password || '');
  const [playerName, setPlayerName] = useState('');
  const [phase, setPhase] = useState('login');
  const [loginView, setLoginView] = useState(urlInfo.roomCode ? 'join' : 'menu');
  const [playerBoard, setPlayerBoard] = useState(createEmptyBoard);
  const [opponentBoard, setOpponentBoard] = useState(createEmptyBoard);
  const [currentTurn, setCurrentTurn] = useState(null);
  const [playerId, setPlayerId] = useState(null);
  const [opponentName, setOpponentName] = useState('');
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('info');
  const [winner, setWinner] = useState(null);
  const [shipsPlaced, setShipsPlaced] = useState(0);
  const [clientPlacements, setClientPlacements] = useState([]);
  const [isReady, setIsReady] = useState(false);
  const [opponentReady, setOpponentReady] = useState(false);
  const [playAgainPending, setPlayAgainPending] = useState(false);
  const [opponentWantsPlayAgain, setOpponentWantsPlayAgain] = useState(false);
  const [placementKey, setPlacementKey] = useState(0);
  const [availableRooms, setAvailableRooms] = useState([]);
  const [loadingRooms, setLoadingRooms] = useState(false);
  const [roomNotFound, setRoomNotFound] = useState(false);
  const [createPassword, setCreatePassword] = useState('');
  const [selectedRoom, setSelectedRoom] = useState(null);
  const [joinRoomCode, setJoinRoomCode] = useState('');
  const [joinRoomPin, setJoinRoomPin] = useState('');
  const [pendingJoin, setPendingJoin] = useState(null);
  const [explosionCells, setExplosionCells] = useState([]);

  // New feature state
  const [theme, setTheme] = useState(() => localStorage.getItem('battleship-theme') || 'dark');
  const [soundEnabled, setSoundEnabled] = useState(() => {
    const val = localStorage.getItem('battleship-sound');
    if (val === null) return false; // Default: disabled until user enables
    return val === 'on';
  });
  const [musicEnabled, setMusicEnabled_] = useState(() => {
    const val = localStorage.getItem('battleship-music');
    if (val === null) return false; // Default: disabled until user enables
    return val === 'on';
  });
  const [chatMessages, setChatMessages] = useState([]);
  const [chatOpen, setChatOpen] = useState(false);
  const [chatUnread, setChatUnread] = useState(0);
  const [isSpectator, setIsSpectator] = useState(false);
  const [spectatorCount, setSpectatorCount] = useState(0);
  const [gameTimeLimit, setGameTimeLimit] = useState(300);
  const [playerTimeLeft, setPlayerTimeLeft] = useState({});
  const [turnStartedAt, setTurnStartedAt] = useState(null);
  const [lastShot, setLastShot] = useState(null);
  const [spectatorBoards, setSpectatorBoards] = useState([]);

  // Refs for socket handlers to avoid stale closures
  const playerSunk = useRef(new Set());
  const opponentSunk = useRef(new Set());
  const playerIdRef = useRef(null);
  const soundRef = useRef(true);
  const chatOpenRef = useRef(false);
  const phaseRef = useRef('login');
  const musicEnabledRef = useRef(true);
  const winnerRef = useRef(null);

  // Consolidated ref sync — single effect avoids 6 separate mount/update cycles
  useEffect(() => {
    playerIdRef.current = playerId;
    soundRef.current = soundEnabled;
    chatOpenRef.current = chatOpen;
    phaseRef.current = phase;
    musicEnabledRef.current = musicEnabled;
    winnerRef.current = winner;
  });

  // Persistence
  useEffect(() => {
    if (playerName) localStorage.setItem('battleship-name', playerName);
  }, [playerName]);

  useEffect(() => {
    localStorage.setItem('battleship-theme', theme);
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('battleship-sound', soundEnabled ? 'on' : 'off');
  }, [soundEnabled]);

  // Music persistence & phase-specific music
  useEffect(() => {
    localStorage.setItem('battleship-music', musicEnabled ? 'on' : 'off');
    setMusicEnabled(musicEnabled);
  }, [musicEnabled]);

  // Initialize music system on mount
  useEffect(() => {
    console.log('[Music Init] Setting music enabled:', musicEnabled);
    setMusicEnabled(musicEnabled);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Play phase-appropriate background music (mirrors Android MusicManager)
  useEffect(() => {
    console.log('[Phase Change] New phase:', phase);
    if (phase === 'gameOver') {
      // Determine victory vs defeat music
      playPhaseMusic(winnerRef.current === playerIdRef.current ? 'victory' : 'defeat');
    } else {
      // Normalize login and waiting to 'menu' to prevent restart on transition
      const musicPhase = (phase === 'login' || phase === 'waiting') ? 'menu' : phase;
      console.log('[Phase Change] Playing music phase:', musicPhase);
      playPhaseMusic(musicPhase);
    }
  }, [phase]);

  // Tab visibility: pause/resume music when switching tabs (mirrors Android onPause/onResume)
  useEffect(() => {
    const handleVisibility = () => {
      if (document.hidden) {
        pauseMusic();
      } else {
        resumeMusic();
      }
    };
    document.addEventListener('visibilitychange', handleVisibility);
    return () => document.removeEventListener('visibilitychange', handleVisibility);
  }, []);

  // Load saved name on mount
  useEffect(() => {
    const saved = localStorage.getItem('battleship-name');
    if (saved && !playerName) setPlayerName(saved);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // If opened via a URL room link, check up-front whether the room exists
  useEffect(() => {
    if (!urlInfo.roomCode) return;
    fetch(`${SOCKET_URL}/rooms/${urlInfo.roomCode}`)
      .then(r => r.json())
      .then(data => { if (!data.exists) setRoomNotFound(true); })
      .catch(() => { });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const resetSunk = useCallback(() => {
    playerSunk.current = new Set();
    opponentSunk.current = new Set();
  }, []);

  const overlay = useCallback((rawBoard, sunkSet) => {
    if (sunkSet.size === 0) return rawBoard;
    return rawBoard.map((row, ri) =>
      row.map((cell, ci) => {
        const key = `${ri},${ci}`;
        if (sunkSet.has(key)) return CELL.SUNK;
        if (sunkSet.has(key + '_safe') && (cell === CELL.WATER || cell === CELL.MISS)) return CELL.SAFE;
        return cell;
      })
    );
  }, []);

  // Socket Handlers
  useEffect(() => {
    if (!socket) return;

    socket.on('gameJoined', (data) => {
      setPlayerId(data.playerId);
      playerIdRef.current = data.playerId;
      const roomCode = data.roomId || '';
      const roomPwd = data.password || '';
      setGameId(roomCode);
      setRoomPassword(roomPwd);
      setURLRoom(roomCode, roomPwd || null);
      setShipsPlaced(0);
      setClientPlacements([]);
      resetSunk();
      setIsReady(false);
      setOpponentReady(false);
      setPlayerBoard(data.board || createEmptyBoard());
      if (data.timeLimit) setGameTimeLimit(data.timeLimit);
      setChatMessages([]);
      setChatUnread(0);
      setIsSpectator(false);
      if (data.players.length === 2) {
        const opp = data.players.find(p => p.id !== data.playerId);
        setOpponentName(opp?.name || 'Opponent');
        setPhase('placement');
        setMessage('🎮 Both players in! Place your ships.');
        setMessageType('success');
      } else {
        setPhase('waiting');
        setMessage('');
      }
    });

    socket.on('playerJoined', (data) => {
      const myId = playerIdRef.current;
      const opp = data.players.find(p => p.id !== myId);
      if (opp) setOpponentName(opp.name || 'Opponent');
      const shouldStartPlacement = data.playerCount === 2 || data.state === 'PLACEMENT_PHASE' || data.players.length === 2;
      if (shouldStartPlacement) {
        setPhase('placement');
        setIsReady(false);
        setOpponentReady(false);
        setMessage('🎮 Opponent joined! Place your ships.');
        setMessageType('success');
      }
    });

    socket.on('error', (data) => {
      const errorMsg = data.error || 'Unknown error';
      setMessage(`❌ ${errorMsg}`);
      setMessageType('error');
      if (errorMsg.includes('does not exist') || errorMsg.includes('Incorrect password') || errorMsg.includes('not found')) {
        setLoginView('join');
        setGameId('');
        setRoomPassword('');
        setPendingJoin(null);
        setURLRoom(null);
      }
    });

    socket.on('placementFinished', () => {
      setIsReady(true);
      setMessage('⏳ Waiting for opponent to finish placing…');
      setMessageType('info');
    });

    socket.on('playerReady', (data) => {
      if (data.playerId !== playerIdRef.current) setOpponentReady(true);
    });

    socket.on('placementUnreadied', () => {
      setIsReady(false);
      setMessage('');
      setMessageType('info');
    });

    socket.on('playerUnreadied', (data) => {
      if (data.playerId !== playerIdRef.current) setOpponentReady(false);
    });

    socket.on('battleStarted', (data) => {
      setPhase('battle');
      setCurrentTurn(data.currentTurn);
      if (data.playerBoard) setPlayerBoard(data.playerBoard);
      setOpponentBoard(createEmptyBoard());
      resetSunk();
      if (data.playerTimeLeft) setPlayerTimeLeft(data.playerTimeLeft);
      if (data.turnStartedAt) setTurnStartedAt(data.turnStartedAt);
      if (data.timeLimit) setGameTimeLimit(data.timeLimit);
      // Play turn notification if it's our turn first
      if (soundRef.current && data.currentTurn === playerIdRef.current) playSound('turn');
    });

    socket.on('shotResult', (data) => {
      setCurrentTurn(data.currentTurn);
      if (data.playerTimeLeft) setPlayerTimeLeft(data.playerTimeLeft);
      if (data.turnStartedAt) setTurnStartedAt(data.turnStartedAt);
      const iShot = data.shooterId === playerIdRef.current;

      // Last shot animation
      const shotBoard = iShot ? 'opponent' : 'player';
      setLastShot({ row: data.row, col: data.col, board: shotBoard });
      setTimeout(() => setLastShot(null), 500);

      // Sound effects
      if (soundRef.current) {
        if (data.shipSunk) playSound('sunk');
        else if (data.isHit) playSound('hit');
        else playSound('miss');
        // Play turn notification when it becomes our turn (opponent missed)
        if (!iShot && !data.isHit && data.currentTurn === playerIdRef.current) {
          setTimeout(() => playSound('turn'), 400);
        }
      }

      // Haptics
      if (data.isHit && !iShot) navigator.vibrate?.(200);
      if (data.shipSunk && !iShot) navigator.vibrate?.([100, 50, 200]);

      if (data.shipSunk && data.sunkShipCells?.length > 0) {
        const ref = iShot ? opponentSunk : playerSunk;
        data.sunkShipCells.forEach(c => ref.current.add(`${c.row},${c.col}`));
        getSurroundingKeys(data.sunkShipCells).forEach(k => ref.current.add(k + '_safe'));

        const boardType = iShot ? 'opponent' : 'player';
        const newExplosions = data.sunkShipCells.map(c => ({
          row: c.row,
          col: c.col,
          board: boardType,
          id: `${boardType}-${c.row}-${c.col}-${Date.now()}`
        }));
        setExplosionCells(prev => [...prev, ...newExplosions]);
        setTimeout(() => {
          setExplosionCells(prev => prev.filter(e => !newExplosions.some(n => n.id === e.id)));
        }, 1500);
      }

      const raw_p = data.playerBoard || createEmptyBoard();
      const raw_o = data.opponentBoard || createEmptyBoard();
      setPlayerBoard(overlay(raw_p, playerSunk.current));
      setOpponentBoard(overlay(raw_o, opponentSunk.current));

      const shipName = data.sunkShipName || 'ship';
      let msg = data.shipSunk
        ? (iShot ? `💥 You sunk their ${shipName}! 🎯 Shoot again!` : `💀 Your ${shipName} was sunk! Opponent shoots again.`)
        : data.isHit
          ? (iShot ? '🔥 Hit! 🎯 Shoot again!' : '🔥 They hit your ship! They shoot again.')
          : (iShot ? '💧 Miss — opponent\'s turn.' : '🛡️ They missed! Your turn.');
      setMessage(msg);
      setMessageType(data.isHit ? (iShot ? 'success' : 'error') : (iShot ? 'info' : 'success'));
      if (data.gameWon) {
        setPhase('gameOver');
        setWinner(data.winner);
        if (soundRef.current) playSound(data.winner === playerIdRef.current ? 'victory' : 'defeat');
      }
    });

    socket.on('gameReset', (data) => {
      setPhase('placement');
      setPlayerBoard(createEmptyBoard());
      setOpponentBoard(createEmptyBoard());
      setCurrentTurn(null);
      setWinner(null);
      setShipsPlaced(0);
      setClientPlacements([]);
      resetSunk();
      setIsReady(false);
      setOpponentReady(false);
      setPlayAgainPending(false);
      setOpponentWantsPlayAgain(false);
      setPlacementKey(k => k + 1);
      setTurnStartedAt(null);
      setPlayerTimeLeft({});
      setChatMessages([]);
      if (data?.timeLimit) setGameTimeLimit(data.timeLimit);
      setMessage('🎮 New game! Place your ships.');
      setMessageType('info');
    });

    socket.on('playerLeft', (data) => {
      setMessage(`👋 ${data.playerName || 'Opponent'} left the game`);
      setMessageType('info');
      setPlayAgainPending(false);
      setOpponentWantsPlayAgain(false);
      setTimeout(() => {
        setPhase('login'); setGameId(''); setPlayerName(''); resetSunk();
        setURLRoom(null);
      }, 2000);
    });

    // Opponent left during placement or game-over — room reset to waiting
    socket.on('opponentLeft', (data) => {
      setPlayAgainPending(false);
      setOpponentWantsPlayAgain(false);
      setIsReady(false);
      setOpponentReady(false);
      setClientPlacements([]);
      setShipsPlaced(0);
      setPlacementKey(k => k + 1);
      setOpponentName('');
      setOpponentBoard(createEmptyBoard());
      setPlayerBoard(createEmptyBoard());
      resetSunk();
      setWinner(null);
      setTurnStartedAt(null);
      setPlayerTimeLeft({});
      setMessage(`⏳ ${data.playerName || 'Opponent'} left — waiting for a new opponent`);
      setMessageType('info');
      setPhase('waiting');
    });

    socket.on('leftRoom', () => {
      setPhase('login'); setGameId(''); setPlayerName(''); resetSunk();
      setURLRoom(null);
      setMessage(''); setMessageType('info');
    });

    socket.on('gameForfeited', (data) => {
      setPhase('gameOver');
      setWinner(data.winner);
      const iForfeited = data.forfeiterId === playerIdRef.current;
      setMessage(iForfeited ? '🏳️ You surrendered' : `🏳️ ${data.forfeiterName} surrendered`);
      setMessageType(iForfeited ? 'info' : 'success');
    });

    socket.on('playAgainRequested', () => setOpponentWantsPlayAgain(true));

    socket.on('playAgainDeclined', () => {
      setPlayAgainPending(false);
      setOpponentWantsPlayAgain(false);
      setMessage('🚫 Opponent declined the rematch');
      setMessageType('error');
    });

    socket.on('chatMessage', (msg) => {
      const isMine = msg.senderId === playerIdRef.current;
      setChatMessages(prev => [...prev, { ...msg, isMine }]);
      if (!isMine && !chatOpenRef.current) {
        setChatUnread(prev => prev + 1);
        if (soundRef.current) playSound('chat');
      }
    });

    socket.on('spectatorJoined', (data) => {
      setIsSpectator(true);
      setSpectatorBoards(data.boards || []);
      setGameTimeLimit(data.timeLimit || 300);
      if (data.playerTimeLeft) setPlayerTimeLeft(data.playerTimeLeft);
      if (data.turnStartedAt) setTurnStartedAt(data.turnStartedAt);
      setCurrentTurn(data.currentTurn);
      if (data.state === 'BATTLE_PHASE') setPhase('battle');
      else if (data.state === 'PLACEMENT_PHASE') setPhase('placement');
      else if (data.state === 'GAME_OVER') setPhase('gameOver');
      const names = (data.players || []).map(p => p.name).join(' vs ');
      setMessage(`👁️ Spectating: ${names}`);
      setMessageType('info');
    });

    socket.on('spectatorShotResult', (data) => {
      setSpectatorBoards(data.boards || []);
      setCurrentTurn(data.currentTurn);
      if (data.playerTimeLeft) setPlayerTimeLeft(data.playerTimeLeft);
      if (data.turnStartedAt) setTurnStartedAt(data.turnStartedAt);
      if (data.gameWon) { setPhase('gameOver'); setWinner(data.winner); }
    });

    socket.on('spectatorBattleStarted', (data) => {
      setPhase('battle');
      setSpectatorBoards(data.boards || []);
      setCurrentTurn(data.currentTurn);
      if (data.playerTimeLeft) setPlayerTimeLeft(data.playerTimeLeft);
      if (data.turnStartedAt) setTurnStartedAt(data.turnStartedAt);
      if (data.timeLimit) setGameTimeLimit(data.timeLimit);
    });

    socket.on('spectatorUpdate', (data) => {
      setSpectatorCount(data.count || 0);
    });

    socket.on('timeUp', (data) => {
      setPhase('gameOver');
      setWinner(data.winner);
      const myId = playerIdRef.current;
      const iLost = data.loser === myId;
      const msg = iLost ? "⏰ Your clock ran out! You lose." : "⏰ Opponent's clock ran out! You win!";
      setMessage(msg);
      setMessageType(iLost ? 'error' : 'success');
      if (soundRef.current) playSound(data.winner === myId ? 'victory' : 'defeat');
    });

    return () => {
      socket.off('gameJoined');
      socket.off('playerJoined');
      socket.off('error');
      socket.off('placementFinished');
      socket.off('playerReady');
      socket.off('placementUnreadied');
      socket.off('playerUnreadied');
      socket.off('battleStarted');
      socket.off('shotResult');
      socket.off('gameReset');
      socket.off('playerLeft');
      socket.off('opponentLeft');
      socket.off('leftRoom');
      socket.off('gameForfeited');
      socket.off('playAgainRequested');
      socket.off('playAgainDeclined');
      socket.off('chatMessage');
      socket.off('spectatorJoined');
      socket.off('spectatorShotResult');
      socket.off('spectatorBattleStarted');
      socket.off('spectatorUpdate');
      socket.off('timeUp');
    };
  }, [socket, overlay, resetSunk]);

  const dispPlayer = useMemo(() => overlay(playerBoard, playerSunk.current), [playerBoard, overlay]);
  const dispOpponent = useMemo(() => overlay(opponentBoard, opponentSunk.current), [opponentBoard, overlay]);

  const fetchRooms = useCallback(async () => {
    setLoadingRooms(true);
    try {
      const res = await fetch(`${SOCKET_URL}/rooms`);
      const data = await res.json();
      setAvailableRooms(data.rooms || []);
    } catch (err) {
      setAvailableRooms([]);
      setMessage('⚠️ Failed to load rooms list');
      setMessageType('error');
    }
    setLoadingRooms(false);
  }, []);

  useEffect(() => {
    if (phase === 'login' && loginView === 'join') fetchRooms();
  }, [phase, loginView, fetchRooms]);

  const handleJoinGame = useCallback((e) => {
    if (e) e.preventDefault();
    const id = joinRoomCode.trim();
    if (!id) { setMessage('❌ Room code required'); setMessageType('error'); return; }
    setPendingJoin({ roomId: id, password: joinRoomPin || null });
    setLoginView('enterName');
  }, [joinRoomCode, joinRoomPin]);

  const handleFinalJoin = useCallback(() => {
    const name = playerName.trim();
    if (!name) { setMessage('❌ Enter your name first'); setMessageType('error'); return; }
    if (!pendingJoin) return;
    setGameId(pendingJoin.roomId);
    setRoomPassword(pendingJoin.password || '');
    socket?.emit('joinGame', {
      gameId: pendingJoin.roomId,
      playerName: name,
      password: pendingJoin.password,
      isCreating: pendingJoin.isCreating,
      isSpectating: pendingJoin.isSpectating || false,
      timeLimit: pendingJoin.timeLimit || gameTimeLimit,
    });
  }, [playerName, pendingJoin, socket, gameTimeLimit]);

  const handleShipPlaced = useCallback((placements) => {
    setClientPlacements(placements);
    setShipsPlaced(placements.length);
  }, []);

  const handleFinishPlace = useCallback(() => {
    const ships = clientPlacements.map((p, i) => ({
      row: p.row, col: p.col, length: p.length, direction: p.direction,
      name: SHIPS[p.shipId]?.name || `Ship ${i + 1}`,
    }));
    socket?.emit('finishPlacement', { ships });
  }, [socket, clientPlacements]);

  const handleUnready = useCallback(() => socket?.emit('unreadyPlacement'), [socket]);

  const handleShoot = useCallback((r, c) => {
    if (socket && currentTurn === playerId) socket.emit('shoot', { row: r, col: c });
  }, [socket, currentTurn, playerId]);

  const handlePlayAgain = useCallback(() => {
    setPlayAgainPending(true);
    socket?.emit('requestPlayAgain');
  }, [socket]);

  const handleForfeit = useCallback(() => {
    if (window.confirm('Are you sure you want to surrender? This will count as a loss.')) {
      socket?.emit('forfeit');
    }
  }, [socket]);

  const handleBackToMenu = useCallback(() => {
    socket?.emit('leaveRoom');
    stopAllMusic();
    setPhase('login'); setGameId(''); setPlayerName(''); resetSunk();
    setLoginView('menu'); setRoomPassword(''); setCreatePassword('');
    setURLRoom(null);
    setIsSpectator(false); setSpectatorCount(0); setSpectatorBoards([]);
    setChatMessages([]); setChatOpen(false); setChatUnread(0);
    setTurnStartedAt(null); setPlayerTimeLeft({});
  }, [socket, resetSunk]);

  const sendChat = useCallback((text) => {
    if (!text.trim() || !socket) return;
    socket.emit('sendChat', { message: text.trim() });
  }, [socket]);

  const handleChatToggle = useCallback(() => {
    setChatOpen(o => !o);
    if (!chatOpenRef.current) setChatUnread(0);
  }, []);

  const toggleTheme = useCallback(() => {
    setTheme(t => t === 'dark' ? 'light' : 'dark');
  }, []);

  const toggleSound = useCallback(() => {
    setSoundEnabled(s => !s);
  }, []);

  const toggleMusic = useCallback(() => {
    setMusicEnabled_(m => !m);
  }, []);

  const handleDeclinePlayAgain = useCallback(() => {
    socket?.emit('declinePlayAgain');
    setPlayAgainPending(false);
    setOpponentWantsPlayAgain(false);
  }, [socket]);

  const noop = useCallback(() => { }, []);

  const isMyTurn = currentTurn === playerId;
  const msgClass = {
    info: 'border-blue-500 bg-blue-500/10 text-blue-200',
    success: 'border-emerald-500 bg-emerald-500/10 text-emerald-200',
    error: 'border-red-500 bg-red-500/10 text-red-300'
  }[messageType] || '';

  return (
    <div className="min-h-screen theme-bg text-white" data-theme={theme}>
      <ConnectionOverlay isConnected={isConnected} />
      <header className="theme-header bg-gradient-to-r from-blue-800 via-blue-700 to-purple-700 border-b-2 border-yellow-500/80 shadow-xl relative overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-r from-blue-600/10 via-transparent to-purple-600/10" />
        <div className="max-w-5xl mx-auto px-3 sm:px-6 py-2.5 sm:py-3.5 flex items-center justify-between gap-3 relative">
          <div className="flex items-center gap-2.5">
            <span className="text-2xl sm:text-3xl drop-shadow-lg">⚔️</span>
            <div>
              <h1 className="text-lg sm:text-2xl font-black tracking-tight leading-none drop-shadow-sm">Battleships</h1>
              <p className="text-blue-200/60 text-[0.6rem] hidden sm:block font-medium tracking-wide">Multiplayer · Real-time</p>
            </div>
          </div>
          <div className="flex items-center gap-1.5">
            <button onClick={toggleSound} className="p-1.5 rounded-lg hover:bg-white/10 active:scale-95 transition text-lg" title={soundEnabled ? 'Mute sounds' : 'Unmute sounds'}>
              {soundEnabled ? '🔊' : '🔇'}
            </button>
            <button onClick={toggleMusic} className="p-1.5 rounded-lg hover:bg-white/10 active:scale-95 transition text-lg" title={musicEnabled ? 'Mute music' : 'Unmute music'}>
              {musicEnabled ? '🎵' : '🔕'}
            </button>
            <button onClick={toggleTheme} className="p-1.5 rounded-lg hover:bg-white/10 active:scale-95 transition text-lg" title="Toggle theme">
              {theme === 'dark' ? '☀️' : '🌙'}
            </button>
            <div className={`flex items-center gap-1.5 px-2 py-1 rounded-full text-xs font-semibold ${isConnected ? 'bg-green-500/20 text-green-300' : 'bg-red-500/20 text-red-300'}`}>
              <span className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-green-400 animate-pulse' : 'bg-red-400'}`} />
              <span className="hidden sm:inline">{isConnected ? 'Online' : 'Offline'}</span>
            </div>
            {phase !== 'login' && playerName && (
              <div className="text-right leading-none">
                <p className="text-sm font-bold">{playerName}</p>
                {gameId && <p className="text-[0.6rem] text-yellow-300 font-mono tracking-wider">{gameId}</p>}
              </div>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-3 sm:px-6 py-4 sm:py-5 space-y-3 sm:space-y-4">
        {message && (
          <div className={`border-l-4 px-4 py-2.5 rounded-lg text-sm font-semibold animate-fade-in backdrop-blur-sm ${msgClass}`}>
            {message}
          </div>
        )}

        {phase === 'login' && (
          <LoginView
            loginView={loginView} gameId={gameId} roomPassword={roomPassword} playerName={playerName}
            setLoginView={setLoginView} setGameId={setGameId} setRoomPassword={setRoomPassword} setPlayerName={setPlayerName}
            createPassword={createPassword} setCreatePassword={setCreatePassword}
            joinRoomCode={joinRoomCode} setJoinRoomCode={setJoinRoomCode}
            joinRoomPin={joinRoomPin} setJoinRoomPin={setJoinRoomPin}
            availableRooms={availableRooms} loadingRooms={loadingRooms} fetchRooms={fetchRooms}
            selectedRoom={selectedRoom} setSelectedRoom={setSelectedRoom}
            handleJoinGame={handleJoinGame} handleFinalJoin={handleFinalJoin}
            pendingJoin={pendingJoin} setPendingJoin={setPendingJoin}
            setMessage={setMessage} setMessageType={setMessageType}
            SOCKET_URL={SOCKET_URL} setURLRoom={setURLRoom}
            gameTimeLimit={gameTimeLimit} setGameTimeLimit={setGameTimeLimit}
            roomNotFound={roomNotFound}
          />
        )}

        {phase === 'waiting' && <WaitingRoom gameId={gameId} roomPassword={roomPassword} handleBackToMenu={handleBackToMenu} timeLimit={gameTimeLimit} />}

        {phase === 'placement' && (
          <div className="space-y-3 animate-fade-in">
            <div className="bg-gradient-to-r from-slate-800/80 to-slate-900/60 rounded-2xl p-3 sm:p-4 border border-slate-700/80 flex flex-wrap items-center justify-between gap-3 shadow-lg">
              <div>
                <h2 className="text-lg sm:text-xl font-black flex items-center gap-2">🎖️ Place Your Fleet</h2>
                <p className="text-slate-400 text-xs mt-0.5">Ships need 1-cell gap including corners</p>
              </div>
              <div className="flex items-center gap-2 sm:gap-3 flex-wrap">
                {gameId && (
                  <div className="bg-slate-700/80 border border-yellow-500/50 rounded-xl px-3 py-1.5 text-center">
                    <p className="text-[0.55rem] text-yellow-400 uppercase tracking-widest">Code</p>
                    <p className="text-base font-mono font-black text-yellow-300 tracking-widest">{gameId}</p>
                  </div>
                )}
                <button
                  onClick={isReady ? handleUnready : handleFinishPlace}
                  disabled={!isReady && shipsPlaced < 5}
                  className={`px-4 py-2 rounded-xl font-bold text-sm transition-all ${isReady && !opponentReady
                    ? 'bg-yellow-500 hover:bg-yellow-400 text-white hover:scale-105 shadow-md'
                    : isReady && opponentReady
                      ? 'bg-green-700 text-green-200 cursor-not-allowed'
                      : shipsPlaced >= 5
                        ? 'bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-400 hover:to-emerald-500 text-white hover:scale-105 shadow-md'
                        : 'bg-slate-700 text-slate-500 cursor-not-allowed'
                    }`}
                >
                  {isReady ? (opponentReady ? '✅ Locked in' : '↩️ Unready') : `✅ Ready ${shipsPlaced}/5`}
                </button>
                <button onClick={handleBackToMenu} className="px-3 py-2 bg-red-900/40 hover:bg-red-800/50 text-red-300 text-xs font-semibold rounded-xl transition border border-red-700/40">🚪</button>
              </div>
            </div>
            <div className={`text-center text-xs py-2 rounded-lg ${opponentReady ? 'bg-emerald-900/30 text-emerald-300' : 'bg-slate-800/50 text-slate-400'}`}>
              {opponentReady ? `✅ ${opponentName} is ready!` : `⏳ Waiting for ${opponentName} to place ships…`}
            </div>
            <ShipPlacement key={placementKey} onShipPlaced={handleShipPlaced} locked={isReady} />
          </div>
        )}

        {phase === 'battle' && (
          <BattleField
            isMyTurn={isMyTurn} opponentName={opponentName} handleForfeit={isSpectator ? noop : handleForfeit}
            dispPlayer={isSpectator ? (spectatorBoards[0]?.board || dispPlayer) : dispPlayer}
            dispOpponent={isSpectator ? (spectatorBoards[1]?.board || dispOpponent) : dispOpponent}
            handleShoot={isSpectator ? noop : handleShoot}
            explosionCells={explosionCells} noop={noop}
            playerTimeLeft={playerTimeLeft} turnStartedAt={turnStartedAt}
            myId={isSpectator ? null : playerId} currentTurn={currentTurn}
            spectatorCount={spectatorCount} isSpectator={isSpectator}
            lastShot={lastShot} handleLeave={handleBackToMenu}
          />
        )}

        {phase === 'gameOver' && (
          <GameOver
            winner={winner} playerId={playerId} opponentName={opponentName}
            opponentWantsPlayAgain={opponentWantsPlayAgain} playAgainPending={playAgainPending}
            handlePlayAgain={handlePlayAgain} handleBackToMenu={handleBackToMenu}
            handleDeclinePlayAgain={handleDeclinePlayAgain}
            isSpectator={isSpectator}
          />
        )}
      </main>

      {phase !== 'login' && (
        <ChatBox
          messages={chatMessages}
          onSend={sendChat}
          isOpen={chatOpen}
          onToggle={handleChatToggle}
          unread={chatUnread}
        />
      )}
    </div>
  );
}

export default App;
